proof fn phi_2_always_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}

proof fn phi_3_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_4_invariant_from_false_init(spec: TempPred<int>, next: ActionPred<int>, inv: StatePred<int>)
    requires
        spec.entails(lift_state(|s: int| false)),
        spec.entails(always(lift_action(next))),
    ensures
        spec.entails(always(lift_state(inv))),
{
    init_invariant::<int>(spec, |s: int| false, next, inv);
}

proof fn phi_5_invariant_ignores_next_action(spec: TempPred<int>, init: StatePred<int>, next: ActionPred<int>)
    requires
        forall |s: int| #[trigger] init(s) ==> false,
        spec.entails(lift_state(init)),
        spec.entails(always(lift_action(next))),
    ensures
        spec.entails(always(lift_state(|s: int| false))),
{
    init_invariant::<int>(spec, init, next, |s: int| false);
}
